components.css:
button {
  padding: var(--a-space-md) var(--a-space-lg);
  background: var(--a-primary);
  color: var(--a-surface-base);
  border: none;
  border-radius: var(--a-radius-md);
  cursor: pointer;
  transition: all var(--a-transition-base);
}

button:hover {
  opacity: 0.9;
  transform: translateY(-2px);
}

button.secondary {
  padding: var(--a-space-md) var(--a-space-lg);
  background: transparent;
  color: var(--a-primary);
  border: 2px solid var(--a-primary);
  border-radius: var(--a-radius-md);
  cursor: pointer;
  transition: all var(--a-transition-base);
}

button.secondary:hover {
  background: color-mix(in oklch, var(--a-primary) 10%, transparent);
}

button.ghost {
  padding: var(--a-space-md) var(--a-space-lg);
  background: transparent;
  color: var(--a-text-main);
  border: none;
  border-radius: var(--a-radius-md);
  cursor: pointer;
  transition: all var(--a-transition-base);
}

button.ghost:hover {
  background: var(--a-surface-overlay);
  color: var(--a-primary);
}

button.small {
  padding: var(--a-space-sm) var(--a-space-md);
  font-size: var(--a-text-sm);
  border-radius: var(--a-radius-md);
}

button.large {
  padding: var(--a-space-lg) var(--a-space-2xl);
  font-size: var(--a-text-lg);
  border-radius: var(--a-radius-lg);
}

button span {
  display: inline-flex;
  align-items: center;
  gap: var(--a-space-xs);
}

.button-group {
  display: flex;
  gap: var(--a-space-md);
  flex-wrap: wrap;
}

.button-group button {
  flex: 1;
  min-width: 120px;
}

a {
  color: var(--a-primary);
  text-decoration: underline;
  text-decoration-thickness: 2px;
  text-underline-offset: 4px;
  transition: all var(--a-transition-base);
}

a:hover {
  text-decoration-color: var(--a-primary);
  opacity: 0.8;
}
